import{_ as t,o as s,c as i,ae as a}from"./chunks/framework.D7zHIyZF.js";const p=JSON.parse('{"title":"Modes","description":"","frontmatter":{"title":"Modes"},"headers":[],"relativePath":"modes.md","filePath":"modes.md"}'),o={name:"modes.md"};function l(r,e,n,d,h,c){return s(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="modes" tabindex="-1">Modes <a class="header-anchor" href="#modes" aria-label="Permalink to &quot;Modes&quot;">​</a></h1><p>jai has three execution modes. Each trades off convenience, confidentiality, and compatibility differently. All three modes use a <strong>private PID namespace</strong>, so jailed processes cannot kill or ptrace anything outside the jail.</p><h2 id="casual-mode" tabindex="-1">Casual mode <a class="header-anchor" href="#casual-mode" aria-label="Permalink to &quot;Casual mode&quot;">​</a></h2><p><strong>The default for unnamed jails.</strong> Think of casual mode as easy protection against tools corrupting your <code>.bashrc</code> or deleting all your files. Mind you, <code>rm -rf ~</code> will still wipe out the directory in which you ran jai (but it&#39;s a git repository mirrored elsewhere, right?), but it won&#39;t wipe out your whole home directory.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # default sandbox is casual by default</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mcasual</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # explicit</span></span></code></pre></div><ul><li>Your home directory is mounted as a <strong>copy-on-write overlay</strong>. The jailed process sees your real files, but writes go to <code>$HOME/.jai/default.changes</code> instead of modifying originals, except in the directory where you ran jai.</li><li>Your current working directory grants <strong>full read/write access</strong> to code in the jail (unless suppressed with <code>-D</code>). So files deleted there are really gone.</li><li><code>/tmp</code> and <code>/var/tmp</code> are <strong>private</strong>.</li><li>The rest of the filesystem is <strong>read-only</strong>.</li></ul><p>Casual mode <strong>does not protect confidentiality.</strong> The jailed process runs as your user and can read most of your files. It is designed to prevent easy filesystem damage, not to hide secrets.</p><p>You can hide specific files with the <code>--mask</code> option or by deleting them from the overlay home at <code>/run/jai/$USER/*.home</code>.</p><h2 id="strict-mode" tabindex="-1">Strict mode <a class="header-anchor" href="#strict-mode" aria-label="Permalink to &quot;Strict mode&quot;">​</a></h2><p><strong>The default for named jails.</strong> Think of strict mode as &quot;a real confidentiality step-up.&quot;</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # strict by default (named jail)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mstrict</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # explicit</span></span></code></pre></div><ul><li>The process runs as the <strong>unprivileged <code>jai</code> system user</strong>, not as you.</li><li>Home directory is an <strong>empty private directory</strong> at <code>$HOME/.jai/&lt;name&gt;.home</code>.</li><li>Granted directories (via <code>-d</code> or cwd) are exposed with <strong>id-mapped mounts</strong> — files look like they are owned by <code>jai</code> inside the jail.</li><li>Because the process has a different UID, it <strong>cannot read</strong> files outside your home directory that are only accessible to your user — this is where confidentiality comes from.</li></ul><p>Strict mode requires the <code>jai</code> system user to exist. It <strong>does not work with NFS</strong> filesystems, because NFS does not support id-mapped mounts.</p><h2 id="bare-mode" tabindex="-1">Bare mode <a class="header-anchor" href="#bare-mode" aria-label="Permalink to &quot;Bare mode&quot;">​</a></h2><p><strong>A compatibility fallback.</strong> Bare mode exists for systems where strict mode is not available — primarily NFS-backed home directories.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mbare</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span></span></code></pre></div><ul><li>Home directory is an <strong>empty private directory</strong>, like strict mode.</li><li>But the process runs as <strong>your user</strong>, not as <code>jai</code>.</li><li>This means it <strong>cannot</strong> provide confidentiality — the process can still read any file accessible to your UID outside the home directory.</li></ul><p>Use bare mode when you need strict-like home isolation but your filesystem does not support id-mapped mounts.</p><h2 id="default-mode-selection" tabindex="-1">Default mode selection <a class="header-anchor" href="#default-mode-selection" aria-label="Permalink to &quot;Default mode selection&quot;">​</a></h2><p>The default mode for newly created sandboxes is strict, though you can override this in <code>$HOME/.jai/.defaults</code>. Once a sandbox <code>name</code> is created, the default mode for the sandbox is stored in <code>$HOME/.jai/name.jail</code>. When first initializing your account, jai creates a file <code>$HOME/.jai/default.jail</code> that sets the default mode for unnamed sandboxes to casual, but you can change this by running <code>jai --init</code> and editing the files in <code>$HOME/.jai</code> before using any sandboxes.</p><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">Casual</th><th style="text-align:left;">Strict</th><th style="text-align:left;">Bare</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Home directory</strong></td><td style="text-align:left;">Copy-on-write overlay of your real home</td><td style="text-align:left;">Empty private home</td><td style="text-align:left;">Empty private home</td></tr><tr><td style="text-align:left;"><strong>Process UID</strong></td><td style="text-align:left;">Invoking user</td><td style="text-align:left;">Unprivileged <code>jai</code> user</td><td style="text-align:left;">Invoking user</td></tr><tr><td style="text-align:left;"><strong>Confidentiality</strong></td><td style="text-align:left;">Weak — jailed code reads your files</td><td style="text-align:left;">Strong — separate UID blocks access</td><td style="text-align:left;">Weak outside $HOME — same UID as you</td></tr><tr><td style="text-align:left;"><strong>Integrity</strong></td><td style="text-align:left;">Overlay captures writes; originals safe</td><td style="text-align:left;">Full isolation; empty home</td><td style="text-align:left;">Full isolation; empty home</td></tr><tr><td style="text-align:left;"><strong>NFS support</strong></td><td style="text-align:left;">Yes (make <code>$JAI_CONFIG_DIR</code> local)</td><td style="text-align:left;">No (id-mapped mounts unsupported)</td><td style="text-align:left;">Yes</td></tr><tr><td style="text-align:left;"><strong>PID namespace</strong></td><td style="text-align:left;">Private</td><td style="text-align:left;">Private</td><td style="text-align:left;">Private</td></tr><tr><td style="text-align:left;"><strong>Best use case</strong></td><td style="text-align:left;">Quick sandboxing, casual coding help</td><td style="text-align:left;">Multi-tool isolation, API key separation</td><td style="text-align:left;">NFS home directories</td></tr></tbody></table><h2 id="which-mode-should-i-use" tabindex="-1">Which mode should I use? <a class="header-anchor" href="#which-mode-should-i-use" aria-label="Permalink to &quot;Which mode should I use?&quot;">​</a></h2><ul><li><strong>Casual</strong> if you are just starting out and want something better than nothing. The boundary is so light-weight that everything should just work.</li><li><strong>Strict</strong> is what you should really use, because it provides a meaningful level of protection and is still super easy to use. But you will probably want to set up some configuration files in <code>$HOME/.jai</code> to have different configurations and sandboxes for different tools. After the setup, strict mode is basically as easy to use as casual mode.</li><li><strong>Bare</strong> if you need strict-like home isolation but your home directory is on NFS.</li></ul><p>If none of these is sufficient, maybe you need a proper container or VM. See the <a href="/security.html">Security Model</a> for more information or the author&#39;s <a href="./arch-vm.html">VM Setup instructions</a> to do something much more secure.</p>`,25)])])}const g=t(o,[["render",l]]);export{p as __pageData,g as default};
